// The browser object comes directly from the Initialize Browser node
const browserData = $input.item;
const records = $node["Get Foreclosures Needing Property Info"].json;

// Verify we have the browser instance
if (!browserData || !browserData.currentBrowser) {
  throw new Error('No browser instance available. Make sure the Initialize Browser node is working correctly.');
}

console.log('Browser initialized successfully with data:', JSON.stringify(browserData));
console.log('Processing', records.length, 'records');

// Initialize counters and containers
return {
  browser: browserData.currentBrowser,
  records: records,
  processedCount: 0,
  totalCount: records.length,
  results: []
};

// Get the current record to process
const recordIndex = $input.item.processedCount;
const currentRecord = $input.item.records[recordIndex];

// Update the context for this iteration
return {
  ...($input.item),
  currentRecord,
  currentIndex: recordIndex
};

